function validateEntry(entry, index) 
{
    let errors = [];

    // Check if 'id' exists and is a number
    if (typeof entry.id !== 'number') 
    {
    errors.push(`Entry at index ${index} has an invalid 'id' type: Expected 'number', got '${typeof entry.id}'.`);
    }

    // Check if 'name' exists and is a non-empty string
    if (typeof entry.name !== 'string' || entry.name.trim().length === 0) 
    {
    errors.push(`Entry at index ${index} has an invalid 'name': Name is missing or empty.`);
    }

    return errors;
}

function checkAllEntries(entriesArray) 
