    entriesArray.forEach((entry, index) => 
    {
    console.log("Values for Entry and Index are: ", entry, index);
    const entryErrors = validateEntry(entry, index);
    if (entryErrors.length > 0) 
    {
        allValidationErrors.push(...entryErrors);
    }
    });

    return allValidationErrors;
}

