function addErrorEntry(fieldName, fieldValue, fieldReason)
{
    const errorArray = JSON.parse(errorJSON);
    const newEntry = { varField: fieldName, varValue: fieldValue, varReason: fieldReason };
    errorArray.push(newEntry);
    errorJSON = JSON.stringify(errorArray);
}


