if (pm.request.body && pm.request.body.mode === 'raw' && pm.request.body.raw)
{
    const requestBodyJson = JSON.parse(pm.request.body.raw);
    console.log("Request Body JSON:", requestBodyJson);

    // Perform checks on the JSON data

    // CMS Number
    passField = "cmsNumber";
    passValue = requestBodyJson.cmsNumber;
    switch (requestBodyJson.cmsNumber)
    {
        case null:
            passReason = "CMS Number is null";
            addErrorEntry(passField,passValue,passReason);
            break;
        case "":
            passReason = "CMS Number is empty";
            addErrorEntry(passField,passValue,passReason);
            break;
        default:
    };
    if(isNaN(requestBodyJson.cmsNumber))
    {
        passReason = "CMS Number is not a number";
        addErrorEntry(passField,passValue,passReason);
    };
    let cmsNumberString = requestBodyJson.cmsNumber.toString();
    if(cmsNumberString.length > 8)
    {
        passReason = "CMS Number is too long";
        addErrorEntry(passField,passValue,passReason);
    };

    //CMS Account Type
    passField = "accountType";
    passValue = requestBodyJson.accountType;
    switch (requestBodyJson.accountType)
    {
        case null:
            passReason = "Account Type is null";
            addErrorEntry(passField,passValue,passReason);
            break;
        case "":
            passReason = "Account Type is empty";
            addErrorEntry(passField,passValue,passReason);
            break;
        default:
    };
    if (requestBodyJson.accountType.length > 3)
    {
        passReason = "Account Type is too long";
        addErrorEntry(passField,passValue,passReason);
    };
    
    const passAccountTypes = ["CMS","TIM"];
    if(!passAccountTypes.includes(requestBodyJson.accountType))
    {
        passReason = "Invalid Account Type";
        addErrorEntry(passField,passValue,passReason);
    };

    // Is there a validation that is needed on the effective date?  Thought process is that the effective date would need to be today or in the future.

    // Journal Codes are only two characters in length
    passField = "journalCode";
    passValue = requestBodyJson.journalCode;
    if(requestBodyJson.journalCode.length !== 2)
    {
        passReason = "Journal Code is not two characters in length";
        addErrorEntry(passField,passValue,passReason);
    };

    // The postCode is used to identify if it is a debit or credit (0 = debit, 1 = credit)
    const passPassCodes = [0,1];
    passField = "postCode";
    passValue = requestBodyJson.postCode;
    if(!passPassCodes.includes(Number(requestBodyJson.postcode)))
    {
        passReason = "postCode is not a valid value of 1 or 0";
        addErrorEntry(passField,passValue,passReason);
    };

    // This is for validating the amount length is not longer then 13 digits.  Question for this is if this includes decimal points or only the digits in front of the decimal point.  For Oracle, what does the type Number mean compared to something like Double.

    // Entry Date - will this ever be a part of the data passed in for the journal entry?

    // Process Date - will this ever be a part of the data passed in for the journal entry?

    // Balance Date - will this ever be a part of the data passed in for the journal entry?

    // Explanation field cannot be longer than 75 characters
    passField = "Explanation";
    passValue = requestBodyJson.explanation;
    if(requestBodyJson.explanation.length > 75)
    {
        passReason = "Explanation is too long";
        addErrorEntry(passField,passValue,passReason);
    } 

    // Initials
    passField = "Initials";
    passValue = requestBodyJson.initials;
    if(requestBodyJson.initials === undefined)
    {
        //there is nothing to pass for an error unless things change when no initials are passed in
    } else
    {
        switch(requestBodyJson.initials.length)
        {
            case 0:
                break;
            case 2:
                break;
            default:
                passReason = "Initials is not two characters in length";
                addErrorEntry(passField,passValue,passReason);
        };
    };
    // Question: Should the initials allow numbers?  Or should the string being passed in be checked for numbers?

    // ClearCode value - What does this do and what are the acceptable values?
    const passClearCodes = [0,1];
    passField = "clearCode";
    passValue = requestBodyJson.clearCode;
    if(!passClearCodes.includes(Number(requestBodyJson.clearCode)))
    {
        passReason = "postCode is not a valid value of 1 or 0";
        addErrorEntry(passField,passValue,passReason);
    };
    if(isNaN(requestBodyJson.clearCode))
    {
        passReason = "Clear Code is not a number";
        addErrorEntry(passField,passValue,passReason);
    };
} else
